// --- QUOTE: rounding ---
it("premium of 197.5G rounds up to 198G (in MHPCO's favor) (7 runes premium = 198G)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ],
      },
    ],
  };
  const result = runScenario(scenario);
  expect(result.results[0].premium).toBe(198);
});
